-- ============================================-- 修复类型不匹配问题（UUID vs VARCHAR）-- ============================================-- 1. 修改 expenses 表的 user_id 字段类型为 VARCHAR(32)ALTER TABLE expenses ALTER COLUMN user_id TYPE VARCHAR(32);-- 2. 修改 mood_diaries 表的 user_id 字段类型为 VARCHAR(32)ALTER TABLE mood_diaries ALTER COLUMN user_id TYPE VARCHAR(32);-- 3. 修改 notes 表的 user_id 字段类型为 VARCHAR(32)ALTER TABLE notes ALTER COLUMN user_id TYPE VARCHAR(32);-- 4. 修改 weight_records 表的 user_id 字段类型为 VARCHAR(32)ALTER TABLE weight_records ALTER COLUMN user_id TYPE VARCHAR(32);-- 5. 修改 user_novels 表的 user_id 字段类型为 VARCHAR(32)ALTER TABLE user_novels ALTER COLUMN user_id TYPE VARCHAR(32);-- 6. 修改 novels 表的 user_id 字段类型为 VARCHAR(32)（允许NULL）ALTER TABLE novels ALTER COLUMN user_id TYPE VARCHAR(32);-- 7. 删除旧视图（如果存在）DROP VIEW IF EXISTS expenses_with_user;DROP VIEW IF EXISTS mood_diaries_with_user;DROP VIEW IF EXISTS notes_with_user;DROP VIEW IF EXISTS weight_records_with_user;DROP VIEW IF EXISTS user_novels_with_details;DROP VIEW IF EXISTS novel_chapters_with_novel;-- 8. 重新创建视图：消费记录带用户信息CREATE OR REPLACE VIEW expenses_with_user ASSELECT     e.*,    u.username,    u.nickname,    u.emailFROM expenses eLEFT JOIN users u ON e.user_id = u.id;-- 9. 重新创建视图：心情日记带用户信息CREATE OR REPLACE VIEW mood_diaries_with_user ASSELECT     m.*,    u.username,    u.nickname,    u.emailFROM mood_diaries mLEFT JOIN users u ON m.user_id = u.id;-- 10. 重新创建视图：笔记带用户信息CREATE OR REPLACE VIEW notes_with_user ASSELECT     n.*,    u.username,    u.nickname,    u.emailFROM notes nLEFT JOIN users u ON n.user_id = u.id;-- 11. 重新创建视图：体重记录带用户信息CREATE OR REPLACE VIEW weight_records_with_user ASSELECT     w.*,    u.username,    u.nickname,    u.emailFROM weight_records wLEFT JOIN users u ON w.user_id = u.id;-- 12. 重新创建视图：用户书架带小说信息CREATE OR REPLACE VIEW user_novels_with_details ASSELECT     un.*,    n.title as novel_title,    n.author,    n.cover_url,    n.category,    n.status as novel_status,    u.username,    u.nicknameFROM user_novels unLEFT JOIN novels n ON un.novel_id = n.id::textLEFT JOIN users u ON un.user_id = u.id;-- 13. 重新创建视图：小说章节带小说信息CREATE OR REPLACE VIEW novel_chapters_with_novel ASSELECT     nc.*,    n.title as novel_title,    n.author,    n.is_free as novel_is_free,    n.price as novel_priceFROM novel_chapters ncLEFT JOIN novels n ON nc.novel_id = n.id::text;-- 14. 授予匿名用户访问权限GRANT SELECT ON expenses_with_user TO anon;GRANT SELECT ON mood_diaries_with_user TO anon;GRANT SELECT ON notes_with_user TO anon;GRANT SELECT ON weight_records_with_user TO anon;GRANT SELECT ON user_novels_with_details TO anon;GRANT SELECT ON novel_chapters_with_novel TO anon;-- ============================================-- 验证-- ============================================-- 检查字段类型SELECT table_name, column_name, data_type FROM information_schema.columns WHERE table_name IN ('expenses', 'mood_diaries', 'notes', 'weight_records', 'user_novels') AND column_name = 'user_id';-- 测试视图SELECT * FROM expenses_with_user LIMIT 1;